mapper.select:
SELECT n.notice_news_seq ,n.post_type ,n.title ,n.post_date ,n.view_count ,n.top_yn ,n.top_start_date ,n.top_end_date ,n.use_yn ,n.file_seq ,u.name AS rgst_user_name ,n.created_at AS rgst_date_time ,n.updated_at AS upt_date_time ,COALESCE(att.attachment_count, 0) AS attachment_count FROM event.notice_news n LEFT JOIN event.users u ON u.user_seq = n.created_by LEFT JOIN LATERAL ( SELECT COUNT(*) AS attachment_count FROM event.tb_file_dtl d WHERE d.file_seq = n.file_seq AND d.del_yn = 'N' ) att ON TRUE
n.deleted_at IS NULL
AND n.post_type = #{postType}
AND n.use_yn = #{useYn}
AND n.title ILIKE '%' || #{keyword} || '%'
ORDER BY CASE WHEN n.top_yn = 'Y' AND CURRENT_DATE BETWEEN n.top_start_date AND n.top_end_date THEN 0 ELSE 1 END, n.post_date DESC, n.notice_news_seq DESC

mapper.update:
UPDATE event.notice_news
SET  post_type   = #{postType}
    ,title       = #{title}
    ,content     = #{content,jdbcType=VARCHAR}
    ,post_date   = #{postDate}
    ,top_yn      = COALESCE(#{topYn,jdbcType=CHAR}, top_yn)
    ,top_start_date = #{topStartDate,jdbcType=DATE}
    ,top_end_date   = #{topEndDate,jdbcType=DATE}
    ,use_yn      = COALESCE(#{useYn,jdbcType=CHAR}, use_yn)
    ,file_seq    = #{fileSeq,jdbcType=BIGINT}
    ,updated_by  = #{uptUserSeq,jdbcType=BIGINT}
    ,updated_at  = CURRENT_TIMESTAMP
WHERE notice_news_seq = #{noticeNewsSeq}
  AND deleted_at IS NULL

UPDATE event.notice_news
SET  deleted_at = CURRENT_TIMESTAMP
    ,updated_by = #{uptUserSeq,jdbcType=BIGINT}
    ,updated_at = CURRENT_TIMESTAMP
WHERE notice_news_seq = #{noticeNewsSeq}
  AND deleted_at IS NULL
